import os
from typing import Any, Dict

import modal

os.environ["MODAL_ENVIRONMENT"] = "modal-vsdatagen"

app = modal.App("rate-limited-api-gateway")

rate_limit_dict = modal.Dict.from_name(
    "rate-limited-api-gateway-output", create_if_missing=True
)
secret = modal.Secret.from_name("rate-limited-api-gateway-secret")


def _increment_counter(counter_key: str) -> int:
    current_value = rate_limit_dict.get(counter_key, 0) or 0
    new_value = int(current_value) + 1
    rate_limit_dict.put(counter_key, new_value)
    return new_value


@app.cls(secrets=[secret])
class RateLimitedGateway:
    @modal.web_endpoint(method="POST")
    def handle(self, payload: Dict[str, Any]) -> Dict[str, Any]:
        api_key = str(payload.get("api_key", ""))
        configured_key = os.environ.get("GATEWAY_API_KEY", "")
        rate_limit_max = int(os.environ.get("RATE_LIMIT_MAX", "0"))

        total_requests = _increment_counter("total_requests_processed")
        rate_limit_dict.put("gateway_status", "operational")
        rate_limit_dict.put("api_version", "v1")

        if not api_key or api_key != configured_key:
            return {
                "status": "unauthorized",
                "detail": "Invalid API key",
                "total_requests_processed": total_requests,
            }

        request_count_key = f"count:{api_key}"
        current_requests = _increment_counter(request_count_key)

        if rate_limit_max and current_requests > rate_limit_max:
            rate_limit_hits = _increment_counter("rate_limit_hits")
            return {
                "status": "rate_limited",
                "detail": "Rate limit exceeded",
                "current_requests": current_requests,
                "rate_limit_max": rate_limit_max,
                "rate_limit_hits": rate_limit_hits,
            }

        return {
            "status": "ok",
            "detail": "Request accepted",
            "current_requests": current_requests,
            "rate_limit_max": rate_limit_max,
        }


@app.local_entrypoint()
def main() -> None:
    api_key = os.environ.get("GATEWAY_API_KEY", "gateway-key-prod-2024")
    payload = {"api_key": api_key}
    response = RateLimitedGateway().handle.remote(payload)
    print(response)
